// 15분 전 시간 계산
const now = new Date();
const from = new Date(now.getTime() - 15 * 60 * 1000);
return {
  fromISO: from.toISOString(),
  toISO: now.toISOString()
};

const items = $input.all();
const failedResponse = items[0]?.json;
const timeoutResponse = items[1]?.json;
const successResponse = items[2]?.json;

const failedList = failedResponse?.data?.content || [];
const timeoutList = timeoutResponse?.data?.content || [];
const successList = successResponse?.data?.content || [];

const totalFailed = failedList.length;
const totalTimeout = timeoutList.length;
const totalSuccess = successList.length;
const totalExecutions = totalFailed + totalTimeout + totalSuccess;

// 전체 실패율 계산
const overallFailureRate = totalExecutions > 0 
  ? ((totalFailed + totalTimeout) / totalExecutions * 100).toFixed(2)
  : 0;

// Seller별 통계 집계
const sellerStats = {};

[...failedList, ...timeoutList, ...successList].forEach(exec => {
  const sellerId = exec.sellerId;
  if (!sellerStats[sellerId]) {
    sellerStats[sellerId] = { sellerId, failed: 0, timeout: 0, success: 0 };
  }
});

failedList.forEach(exec => {
  sellerStats[exec.sellerId].failed++;
});

timeoutList.forEach(exec => {
  sellerStats[exec.sellerId].timeout++;
});

successList.forEach(exec => {
  sellerStats[exec.sellerId].success++;
});

// 실패율 높은 Seller 탐지 (실패율 30% 이상)
const problematicSellers = Object.values(sellerStats)
  .map(s => {
    const total = s.failed + s.timeout + s.success;
    const failureRate = total > 0 ? ((s.failed + s.timeout) / total * 100) : 0;
    return { ...s, total, failureRate: failureRate.toFixed(2) };
  })
  .filter(s => s.total >= 3 && parseFloat(s.failureRate) >= 30)
  .sort((a, b) => parseFloat(b.failureRate) - parseFloat(a.failureRate));

// 알림 조건
const alerts = [];

if (parseFloat(overallFailureRate) >= 50) {
  alerts.push({
    type: 'CRITICAL',
    metric: 'overall_failure_rate',
    value: overallFailureRate,
    message: `🚨 전체 크롤링 실패율 ${overallFailureRate}%! 시스템 장애 의심`
  });
} else if (parseFloat(overallFailureRate) >= 30) {
  alerts.push({
    type: 'WARNING',
    metric: 'overall_failure_rate',
    value: overallFailureRate,
    message: `⚠️ 전체 크롤링 실패율 ${overallFailureRate}% 주의`
  });
}

if (problematicSellers.length > 0) {
  const sellerList = problematicSellers.slice(0, 5).map(s => 
    `• Seller ${s.sellerId}: ${s.failureRate}% (${s.failed + s.timeout}/${s.total})`
  ).join('\n');

  alerts.push({
    type: problematicSellers.length >= 3 ? 'CRITICAL' : 'WARNING',
    metric: 'seller_failure_rate',
    count: problematicSellers.length,
    message: problematicSellers.length >= 3
      ? `🚨 ${problematicSellers.length}개 Seller 실패율 30% 초과:\n${sellerList}`
      : `⚠️ ${problematicSellers.length}개 Seller 실패율 주의:\n${sellerList}`
  });
}

// 연속 실패 패턴 감지 (같은 Task가 3회 이상 연속 실패)
const taskFailureCounts = {};
[...failedList, ...timeoutList].forEach(exec => {
  const taskId = exec.crawlTaskId;
  taskFailureCounts[taskId] = (taskFailureCounts[taskId] || 0) + 1;
});

const repeatedFailures = Object.entries(taskFailureCounts)
  .filter(([_, count]) => count >= 3)
  .map(([taskId, count]) => ({ taskId, count }));

if (repeatedFailures.length > 0) {
  alerts.push({
    type: 'WARNING',
    metric: 'repeated_failures',
    count: repeatedFailures.length,
    message: `⚠️ ${repeatedFailures.length}개 Task가 반복 실패 중 (3회 이상)`
  });
}

return {
  timestamp: new Date().toISOString(),
  summary: {
    totalExecutions,
    totalFailed,
    totalTimeout,
    totalSuccess,
    overallFailureRate: parseFloat(overallFailureRate),
    problematicSellerCount: problematicSellers.length
  },
  problematicSellers: problematicSellers.slice(0, 10),
  repeatedFailures: repeatedFailures.slice(0, 10),
  alerts,
  hasAlerts: alerts.length > 0,
  hasCritical: alerts.some(a => a.type === 'CRITICAL')
};

const data = $input.first().json;
const alerts = data.alerts;
const summary = data.summary;
const problematicSellers = data.problematicSellers;

const hasCritical = data.hasCritical;
const emoji = hasCritical ? '🚨' : '⚠️';
const color = hasCritical ? '#ff0000' : '#ffcc00';
const alertText = alerts.map(a => a.message).join('\n\n');

let sellerTableText = '';
if (problematicSellers.length > 0) {
  sellerTableText = problematicSellers.slice(0, 5).map(s => 
    `| ${s.sellerId} | ${s.failureRate}% | ${s.failed} | ${s.timeout} | ${s.success} |`
  ).join('\n');
}

const slackMessage = {
  text: `${emoji} CrawlingHub Failure Alert`,
  attachments: [
    {
      color: color,
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: `${emoji} CrawlingHub 크롤링 실패율 알림`,
            emoji: true
          }
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: alertText
          }
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*총 실행*\n${summary.totalExecutions}건`
            },
            {
              type: 'mrkdwn',
              text: `*전체 실패율*\n${summary.overallFailureRate}%`
            },
            {
              type: 'mrkdwn',
              text: `*FAILED*\n${summary.totalFailed}건`
            },
            {
              type: 'mrkdwn',
              text: `*TIMEOUT*\n${summary.totalTimeout}건`
            },
            {
              type: 'mrkdwn',
              text: `*SUCCESS*\n${summary.totalSuccess}건`
            },
            {
              type: 'mrkdwn',
              text: `*문제 Seller*\n${summary.problematicSellerCount}개`
            }
          ]
        },
        {
          type: 'context',
          elements: [
            {
              type: 'mrkdwn',
              text: `⏰ ${data.timestamp} | 최근 15분 기준`
            }
          ]
        }
      ]
    }
  ]
};

return { slackMessage, hasCritical, problematicSellers };
